selector_to_html = {"a[href=\"system.html#volume-settings\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">\u0625\u0639\u062f\u0627\u062f\u0627\u062a \u0627\u0644\u0635\u0648\u062a<a class=\"headerlink\" href=\"#volume-settings\" title=\"Link to this heading\">#</a></h2><p>\u0645\u0633\u062d \u0631\u0645\u0632 \u0627\u0644\u0625\u0639\u062f\u0627\u062f \u0627\u0644\u0645\u0642\u0627\u0628\u0644 \u0644\u062a\u0634\u063a\u064a\u0644/\u0625\u064a\u0642\u0627\u0641 \u0645\u0648\u062c\u0647 \u0627\u0644\u0635\u0648\u062a \u0645\u0646 \u0627\u0644\u0645\u0627\u0633\u062d \u0627\u0644\u0636\u0648\u0626\u064a</p>", "a[href=\"scanmode.html#start-setup\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">\u0628\u062f\u0621 \u0627\u0644\u0625\u0639\u062f\u0627\u062f<a class=\"headerlink\" href=\"#start-setup\" title=\"Link to this heading\">#</a></h2>", "a[href=\"scanmode.html#key-trigger-mode\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">\u0648\u0636\u0639 \u0645\u0634\u063a\u0644 \u0627\u0644\u0645\u0641\u062a\u0627\u062d<a class=\"headerlink\" href=\"#key-trigger-mode\" title=\"Link to this heading\">#</a></h2><p>\u0627\u0636\u063a\u0637 \u0639\u0644\u0649 \u0627\u0644\u0632\u0631 \u0644\u062a\u0634\u063a\u064a\u0644 \u0627\u0644\u0645\u0633\u062d \u0627\u0644\u0636\u0648\u0626\u064a\u060c \u0648\u062a\u062d\u0631\u064a\u0631 \u0627\u0644\u0632\u0631 \u0644\u0625\u0646\u0647\u0627\u0621 \u0627\u0644\u0645\u0633\u062d. \u064a\u0646\u062a\u0647\u064a \u0627\u0644\u0628\u062d\u062b \u0639\u0646\u062f\u0645\u0627 \u064a\u0643\u0648\u0646 \u0627\u0644\u0641\u062d\u0635 \u0646\u0627\u062c\u062d\u0627\u064b \u0623\u0648 \u064a\u062a\u062c\u0627\u0648\u0632 \u0648\u0642\u062a \u0627\u0644\u0642\u0631\u0627\u0621\u0629 \u0648\u0642\u062a \u0627\u0644\u0642\u0631\u0627\u0621\u0629 \u0627\u0644\u0648\u0627\u062d\u062f\u0629.</p>", "a[href=\"barcode.html#id1\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">\u0631\u0645\u0648\u0632 \u062b\u0646\u0627\u0626\u064a\u0629 \u0627\u0644\u0623\u0628\u0639\u0627\u062f<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">#</a></h2>", "a[href=\"scanmode.html#continuous-mode\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">\u0627\u0644\u0648\u0636\u0639 \u0627\u0644\u0645\u0633\u062a\u0645\u0631<a class=\"headerlink\" href=\"#continuous-mode\" title=\"Link to this heading\">#</a></h2><p>\u064a\u0639\u0645\u0644 \u0627\u0644\u0645\u0627\u0633\u062d \u0627\u0644\u0636\u0648\u0626\u064a \u0628\u0627\u0633\u062a\u0645\u0631\u0627\u0631. \u0625\u0630\u0627 \u0646\u062c\u062d \u0627\u0644\u0645\u0633\u062d \u0627\u0644\u0636\u0648\u0626\u064a \u0623\u0648 \u062a\u062c\u0627\u0648\u0632 \u0648\u0642\u062a \u0627\u0644\u0645\u0633\u062d \u0627\u0644\u0636\u0648\u0626\u064a \u0648\u0642\u062a \u0627\u0644\u0639\u0645\u0644 \u0627\u0644\u0648\u0627\u062d\u062f\u060c \u064a\u0646\u062a\u0647\u064a \u0627\u0644\u0645\u0633\u062d \u0627\u0644\u0636\u0648\u0626\u064a \u0627\u0644\u062d\u0627\u0644\u064a. \u0625\u0630\u0627 \u062a\u062c\u0627\u0648\u0632 \u0627\u0644\u0648\u0642\u062a \u0627\u0644\u0648\u0642\u062a \u0627\u0644\u0645\u062d\u062f\u062f \u060c \u064a\u062a\u0645 \u062a\u0634\u063a\u064a\u0644 \u0627\u0644\u0641\u062d\u0635 \u0627\u0644\u062a\u0627\u0644\u064a \u062a\u0644\u0642\u0627\u0626\u064a\u0627\u064b.</p>", "a[href=\"character.html#start-setup\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">\u0628\u062f\u0621 \u0627\u0644\u0625\u0639\u062f\u0627\u062f<a class=\"headerlink\" href=\"#start-setup\" title=\"Link to this heading\">#</a></h2>", "a[href=\"scanmode.html#end-setup\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">\u0625\u0646\u0647\u0627\u0621 \u0627\u0644\u0625\u0639\u062f\u0627\u062f<a class=\"headerlink\" href=\"#end-setup\" title=\"Link to this heading\">#</a></h2>", "a[href=\"scanmode.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">\u0648\u0636\u0639 \u0627\u0644\u0645\u0633\u062d<a class=\"headerlink\" href=\"#scan-mode\" title=\"Link to this heading\">#</a></h1><h2>\u0628\u062f\u0621 \u0627\u0644\u0625\u0639\u062f\u0627\u062f<a class=\"headerlink\" href=\"#start-setup\" title=\"Link to this heading\">#</a></h2>", "a[href=\"#gy-70u\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><strong>GY-70U</strong> \u6709\u7ebf\u626b\u63cf\u67aa\u5feb\u901f\u8bbe\u7f6e\u624b\u518c<a class=\"headerlink\" href=\"#gy-70u\" title=\"Link to this heading\">#</a></h1>", "a[href=\"barcode.html#d-symbologies\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">\u0631\u0645\u0648\u0632 1D<a class=\"headerlink\" href=\"#d-symbologies\" title=\"Link to this heading\">#</a></h2>", "a[href=\"barcode.html#start-setup\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">\u0628\u062f\u0621 \u0627\u0644\u0625\u0639\u062f\u0627\u062f<a class=\"headerlink\" href=\"#start-setup\" title=\"Link to this heading\">#</a></h2>", "a[href=\"system.html#start-setup\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">\u0628\u062f\u0621 \u0627\u0644\u0625\u0639\u062f\u0627\u062f<a class=\"headerlink\" href=\"#start-setup\" title=\"Link to this heading\">#</a></h2>", "a[href=\"character.html#end-setup\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">\u0625\u0646\u0647\u0627\u0621 \u0627\u0644\u0625\u0639\u062f\u0627\u062f<a class=\"headerlink\" href=\"#end-setup\" title=\"Link to this heading\">#</a></h2>", "a[href=\"character.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">\u0627\u0644\u0645\u062f\u062e\u0644<a class=\"headerlink\" href=\"#terminator\" title=\"Link to this heading\">#</a></h1><h2>\u0628\u062f\u0621 \u0627\u0644\u0625\u0639\u062f\u0627\u062f<a class=\"headerlink\" href=\"#start-setup\" title=\"Link to this heading\">#</a></h2>", "a[href=\"character.html#end-character-settings\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">\u0625\u0639\u062f\u0627\u062f\u0627\u062a \u062d\u0631\u0641 \u0627\u0644\u0646\u0647\u0627\u064a\u0629<a class=\"headerlink\" href=\"#end-character-settings\" title=\"Link to this heading\">#</a></h2><p>\u064a\u062a\u0645 \u0625\u0636\u0627\u0641\u0629 \u062d\u0631\u0641 \u0627\u0644\u0646\u0647\u0627\u064a\u0629 \u0628\u0639\u062f \u0641\u0643 \u062a\u0622\u0643\u0644 \u0627\u0644\u0628\u064a\u0627\u0646\u0627\u062a \u0641\u064a \u062a\u0646\u0633\u064a\u0642 \u0627\u0644\u0628\u064a\u0627\u0646\u0627\u062a \u0627\u0644\u0645\u0634\u0637\u0648\u0628\u0629 + \u062d\u0631\u0641 \u0627\u0644\u0646\u0647\u0627\u064a\u0629.</p>", "a[href=\"barcode.html#end-setup\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">\u0625\u0646\u0647\u0627\u0621 \u0627\u0644\u0625\u0639\u062f\u0627\u062f<a class=\"headerlink\" href=\"#end-setup\" title=\"Link to this heading\">#</a></h2>", "a[href=\"barcode.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">\u0627\u0644\u0631\u0645\u0648\u0632<a class=\"headerlink\" href=\"#symbologies\" title=\"Link to this heading\">#</a></h1><h2>\u0628\u062f\u0621 \u0627\u0644\u0625\u0639\u062f\u0627\u062f<a class=\"headerlink\" href=\"#start-setup\" title=\"Link to this heading\">#</a></h2>", "a[href=\"system.html#end-setup\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">\u0625\u0646\u0647\u0627\u0621 \u0627\u0644\u0625\u0639\u062f\u0627\u062f<a class=\"headerlink\" href=\"#end-setup\" title=\"Link to this heading\">#</a></h2>", "a[href=\"system.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">\u0625\u0639\u062f\u0627\u062f\u0627\u062a \u0627\u0644\u0646\u0638\u0627\u0645<a class=\"headerlink\" href=\"#system-settings\" title=\"Link to this heading\">#</a></h1><h2>\u0628\u062f\u0621 \u0627\u0644\u0625\u0639\u062f\u0627\u062f<a class=\"headerlink\" href=\"#start-setup\" title=\"Link to this heading\">#</a></h2>", "a[href=\"scanmode.html#auto-sensing-mode\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">\u0648\u0636\u0639 \u0627\u0644\u0625\u0633\u062a\u0634\u0639\u0627\u0631 \u0627\u0644\u062a\u0644\u0642\u0627\u0626\u064a<a class=\"headerlink\" href=\"#auto-sensing-mode\" title=\"Link to this heading\">#</a></h2><p>\u0641\u064a \u0648\u0636\u0639 \u0627\u0644\u0627\u0633\u062a\u0634\u0639\u0627\u0631 \u0627\u0644\u062a\u0644\u0642\u0627\u0626\u064a\u060c \u0633\u0648\u0641 \u064a\u0643\u062a\u0634\u0641 \u0627\u0644\u0645\u0627\u0633\u062d \u0627\u0644\u0636\u0648\u0626\u064a \u0633\u0637\u0648\u0639 \u0627\u0644\u0628\u064a\u0626\u0629 \u0627\u0644\u0645\u062d\u064a\u0637\u0629. \u0639\u0646\u062f\u0645\u0627 \u064a\u062a\u063a\u064a\u0631 \u0627\u0644\u0633\u0637\u0648\u0639\u060c \u064a\u062a\u0645 \u062a\u0634\u063a\u064a\u0644 \u0627\u0644\u0645\u0633\u062d. \u064a\u0646\u062a\u0647\u064a \u0627\u0644\u0645\u0633\u062d \u0627\u0644\u0636\u0648\u0626\u064a \u0639\u0646\u062f\u0645\u0627 \u064a\u0646\u062c\u062d \u0627\u0644\u0645\u0633\u062d \u0627\u0644\u0636\u0648\u0626\u064a \u0623\u0648 \u0639\u0646\u062f\u0645\u0627 \u064a\u062a\u062c\u0627\u0648\u0632 \u0648\u0642\u062a \u0627\u0644\u0645\u0633\u062d \u0627\u0644\u0636\u0648\u0626\u064a \u0648\u0642\u062a \u0627\u0644\u0639\u0645\u0644 \u0627\u0644\u0648\u0627\u062d\u062f. \u0648\u0628\u0635\u0631\u0641 \u0627\u0644\u0646\u0638\u0631 \u0639\u0645\u0627 \u0625\u0630\u0627 \u0643\u0627\u0646 \u0627\u0644\u0645\u0633\u062d \u0627\u0644\u0623\u062e\u064a\u0631 \u0646\u0627\u062c\u062d\u0627\u064b \u0623\u0648 \u0641\u0627\u0634\u0644\u0627\u064b\u060c \u0633\u064a\u062a\u0645 \u0627\u0643\u062a\u0634\u0627\u0641 \u0633\u0637\u0648\u0639 \u0627\u0644\u0628\u064a\u0626\u0629 \u0627\u0644\u0645\u062d\u064a\u0637\u0629 \u0645\u0631\u0629 \u0623\u062e\u0631\u0649.</p>", "a[href=\"system.html#restore-default-settings\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">\u0625\u0633\u062a\u0639\u0627\u062f\u0629 \u0627\u0644\u0625\u0639\u062f\u0627\u062f\u0627\u062a \u0627\u0644\u0627\u0641\u062a\u0631\u0627\u0636\u064a\u0629<a class=\"headerlink\" href=\"#restore-default-settings\" title=\"Link to this heading\">#</a></h2><p>\u0639\u0646\u062f \u062d\u062f\u0648\u062b \u062e\u0637\u0623 \u063a\u064a\u0631 \u0645\u0639\u0631\u0648\u0641 \u0639\u0644\u0649 \u0627\u0644\u0645\u0627\u0633\u062d \u0627\u0644\u0636\u0648\u0626\u064a\u060c \u064a\u0645\u0643\u0646\u0643 \u0625\u0639\u0627\u062f\u0629 \u062a\u0639\u064a\u064a\u0646 \u0627\u0644\u0645\u0627\u0633\u062d \u0627\u0644\u0636\u0648\u0626\u064a \u0639\u0646 \u0637\u0631\u064a\u0642 \u0627\u0633\u062a\u0639\u0627\u062f\u0629 \u0627\u0644\u0625\u0639\u062f\u0627\u062f\u0627\u062a \u0627\u0644\u0627\u0641\u062a\u0631\u0627\u0636\u064a\u0629.</p>"}
skip_classes = ["headerlink", "sd-stretched-link", "sd-rounded-pill"]

window.onload = function () {
    for (const [select, tip_html] of Object.entries(selector_to_html)) {
        const links = document.querySelectorAll(`article.bd-article ${select}`);
        for (const link of links) {
            if (skip_classes.some(c => link.classList.contains(c))) {
                continue;
            }

            tippy(link, {
                content: tip_html,
                allowHTML: true,
                arrow: true,
                placement: 'auto-start', maxWidth: 500, interactive: false,

            });
        };
    };
    console.log("tippy tips loaded!");
};
